func (rf *Raft) InstallSnapshot(args *InstallSnapshotArgs, reply *InstallSnapshotReply) {
// ... check term ...

pre.code:
// If snapshot is ahead of our entire log:
if args.LastIncludedIndex > rf.log.lastIndex() {
    rf.log.truncateAndReset(args.LastIncludedIndex, args.LastIncludedTerm)
} else {
    // If our log has entries beyond the snapshot:
    // Keep the part of the log that follows the snapshot
    rf.log.discardPrefix(args.LastIncludedIndex)
}

rf.stateMachine.ApplySnapshot(args.Data)
